def knapsack_dp(W, V, M, n):
    B = [[0 for j in range(M+1)] for i in range(n+1)]

    for i in range(1, n+1):
        for j in range(M+1):
            B[i][j] = B[i-1][j]

            if j >= W[i-1]:
                B[i][j] = max(B[i-1][j], B[i-1][j-W[i-1]]+V[i-1])

        print(B[i][j], end=" ")
        print()

    print("最大价值:", B[n][M])

    print("所选物品：")
    while n != 0:
        if B[n][M] != B[n-1][M]:
            print("\t选择第", n, "件物品，重量 =", W[n-1], "，价值 =", V[n-1])
            M = M - W[n-1]

        n -= 1

